export const meta = {
  name: 'stuck-yellow-verify',
  description: 'Verify stuck-yellow dot root cause across watcher, renderer store, host-service path',
  phases: [
    { title: 'Read', detail: 'parallel subsystem readers' },
    { title: 'Verify', detail: 'adversarial check of the hypothesis' },
  ],
}

const FINDINGS = {
  type: 'object',
  required: ['summary', 'facts', 'timerHome', 'risks'],
  properties: {
    summary: { type: 'string' },
    facts: { type: 'array', items: { type: 'object', required: ['claim', 'file', 'evidence'], properties: {
      claim: { type: 'string' }, file: { type: 'string' }, line: { type: 'number' }, evidence: { type: 'string' } } } },
    timerHome: { type: 'string', description: 'assessment: could a periodic stale-sweep live in this subsystem? how?' },
    risks: { type: 'array', items: { type: 'string' } },
  },
}

const CONTEXT = `
BUG: per-terminal agent status dot stuck YELLOW indefinitely. Root cause (confirmed from disk + ~/.superset/logs/dot-decisions.log):
superset-notify.py (Python embedded in apps/desktop/src/main/lib/agent-jsonl-watcher/pane-map-hook.ts) holds yellow at turn end (Stop)
when the payload's background_tasks[] has running AGENT-type entries. Claude Code never marks idle teammates finished, so the hold
relies on a 900s idle reap (_bg_hold_is_stale: mtime of ~/.superset/agent-subagent-running/<terminalId>.bgactive). BUT the reap only
runs inside hook event handlers (Stop/SubagentStop/manual-compact SessionStart). If the session's LAST event is a HOLD (bgactive was
<900s fresh at that moment — live case: 870s) and the user never prompts again, no event ever re-evaluates -> yellow latched forever.
Fix direction: a TIME-based sweep somewhere in the always-running main process (or host-service) that detects .agentbg terminals whose
.bgactive went stale and synthesizes the green/blue turn-end WITHOUT stomping a pending red (askq dir owners) or a codex-companion hold.
Your job: read your assigned subsystem and report structured facts that constrain/enable this fix. Return ONLY facts you verified by reading code, with file:line.
`

phase('Read')
const readers = [
  {
    key: 'watcher',
    prompt: CONTEXT + `
Subsystem: the agent JSONL watcher + pane-map plumbing in apps/desktop/src/main/lib/agent-jsonl-watcher/ (ALL files EXCEPT deep-reading the embedded Python in pane-map-hook.ts — skim its TS wrapper parts only).
Answer: (1) Does the watcher have a poll/interval loop? Where (file:line)? What cadence? (2) What eventTypes can the watcher emit and HOW do they reach the renderer store (IPC? host-service POST? direct emitter)? (3) Does ANY code path in main process emit a turn-end/green (Stop) or BackgroundRunning without a hook event? (4) How does the watcher map session->terminalId (pane map)? Could a sweep resolve terminalId->latest sessionId? (5) Where does the watcher "re-assert yellow if a reaped set still writes" — file:line. (6) Is there existing machinery to read ~/.superset/agent-subagent-running markers from TS? (7) API-ABORT-RELEASE reap — where, what does it emit?`,
  },
  {
    key: 'renderer-store',
    prompt: CONTEXT + `
Subsystem: renderer v2-notifications store. Find resolveV2AgentStatusTransition, applySourceAxes, the DOT-AXES axis model, DOT-PERSIST sessionStorage persistence, and the eventType->axis mapping (map-event-type or similar). Search apps/desktop/src/renderer.
Answer: (1) Exact axis semantics: which eventTypes SET and CLEAR the working axis? Does "Stop" clear working AND set review-green? Does "BackgroundRunning" clear working? (2) Does the permission (red) axis survive a Stop? I.e. if a synthetic Stop is emitted while red is latched, is red stomped? file:line. (3) Any existing time-based decay of any axis in the store? (4) DOT-PERSIST: on renderer reload, are latched yellow axes restored from sessionStorage — meaning a stale yellow survives reload and ONLY a new event clears it? (5) What transport delivers eventTypes into the store (tRPC subscription name, emitter)? (6) Rollup fold: confirm workspace dot derives from per-source primitive only.`,
  },
  {
    key: 'host-service',
    prompt: CONTEXT + `
Subsystem: the host-service hook POST path. superset-notify.py POSTs to $SUPERSET_HOST_AGENT_HOOK_URL. Find the receiving endpoint (search apps/desktop + packages for AGENT_HOOK_URL / agent hook route / lifecycle POST handler), and trace: POST -> ? -> renderer store.
Answer: (1) Endpoint file:line, expected payload shape (terminalId, eventType, sessionId?). (2) What validation/filtering happens (does it drop unknown eventTypes)? (3) Could main-process TS code call the same ingestion function directly (bypassing HTTP) to inject a synthetic event for a terminalId? Name the function/emitter. (4) Is the pane-map (terminal->session) accessible there? (5) Any existing periodic timers in host-service or main that could host a 60s sweep (file:line)?`,
  },
]

const results = await pipeline(
  readers,
  r => agent(r.prompt, { label: 'read:' + r.key, phase: 'Read', schema: FINDINGS }),
  (res, r) => res ? agent(
    CONTEXT + `
An investigator reported these findings about subsystem "${r.key}":
` + JSON.stringify(res, null, 2) + `
Adversarially VERIFY the 3 most load-bearing claims by re-reading the cited files (apps/desktop/...). For each: CONFIRMED or REFUTED with evidence. Also answer: does anything in this subsystem REFUTE the root cause (an existing mechanism that should already have cleared the stuck yellow — e.g. an existing sweep, a watcher green-emit, a renderer decay)? Return JSON {verdicts:[{claim,verdict,evidence}], refutesRootCause: string|null}.`,
    { label: 'verify:' + r.key, phase: 'Verify', schema: {
      type: 'object', required: ['verdicts', 'refutesRootCause'],
      properties: {
        verdicts: { type: 'array', items: { type: 'object', required: ['claim', 'verdict', 'evidence'], properties: { claim: {type:'string'}, verdict: {type:'string'}, evidence: {type:'string'} } } },
        refutesRootCause: { type: ['string', 'null'] },
      },
    } }
  ).then(v => ({ key: r.key, findings: res, verify: v })) : null,
)

return results.filter(Boolean)

